import{_ as i,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"高级功能: 多账户管理 | Antigravity Auth","description":"掌握 Antigravity Auth 插件的高级特性。深入学习多账户负载均衡、智能账户选择、速率限制处理、会话恢复和请求转换等核心机制。","frontmatter":{"title":"高级功能: 多账户管理 | Antigravity Auth","sidebarTitle":"搞定多账户","subtitle":"高级功能: 多账户管理","description":"掌握 Antigravity Auth 插件的高级特性。深入学习多账户负载均衡、智能账户选择、速率限制处理、会话恢复和请求转换等核心机制。","order":3},"headers":[],"relativePath":"zh/NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"zh/NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),r={name:"zh/NoeFabris/opencode-antigravity-auth/advanced/index.md"};function o(n,a,h,s,u,d){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="高级功能" tabindex="-1">高级功能 <a class="header-anchor" href="#高级功能" aria-label="Permalink to &quot;高级功能&quot;">​</a></h1><p>本章节帮助你深入掌握 Antigravity Auth 插件的高级特性，包括多账户负载均衡、智能账户选择、速率限制处理、会话恢复、请求转换等核心机制。无论是优化配额利用率，还是排查复杂问题，这里都有你需要的答案。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确保</p><ul><li>✅ 已完成 <a href="./../start/quick-install/">快速安装</a> 并成功添加第一个账户</li><li>✅ 已完成 <a href="./../start/first-auth-login/">首次认证</a> 并理解 OAuth 流程</li><li>✅ 已完成 <a href="./../start/first-request/">首次请求</a> 并验证插件正常工作</li></ul></div><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><h3 id="_1-多账户设置" tabindex="-1">1. <a href="./multi-account-setup/">多账户设置</a> <a class="header-anchor" href="#_1-多账户设置" aria-label="Permalink to &quot;1. [多账户设置](./multi-account-setup/)&quot;">​</a></h3><p>配置多个 Google 账户，实现配额池化和负载均衡。</p><ul><li>添加多个账户，提升总体配额上限</li><li>理解双配额系统（Antigravity + Gemini CLI）</li><li>根据场景选择合适的账户数量</li></ul><h3 id="_2-账户选择策略" tabindex="-1">2. <a href="./account-selection-strategies/">账户选择策略</a> <a class="header-anchor" href="#_2-账户选择策略" aria-label="Permalink to &quot;2. [账户选择策略](./account-selection-strategies/)&quot;">​</a></h3><p>掌握 sticky、round-robin、hybrid 三种账户选择策略的最佳实践。</p><ul><li>1 个账户 → sticky 策略保留 prompt 缓存</li><li>2-3 个账户 → hybrid 策略智能分布请求</li><li>4+ 个账户 → round-robin 策略最大化吞吐量</li></ul><h3 id="_3-速率限制处理" tabindex="-1">3. <a href="./rate-limit-handling/">速率限制处理</a> <a class="header-anchor" href="#_3-速率限制处理" aria-label="Permalink to &quot;3. [速率限制处理](./rate-limit-handling/)&quot;">​</a></h3><p>理解速率限制检测、自动重试和账户切换机制。</p><ul><li>区分 5 种不同类型的 429 错误</li><li>理解自动重试的指数退避算法</li><li>掌握多账户场景下的自动切换逻辑</li></ul><h3 id="_4-会话恢复" tabindex="-1">4. <a href="./session-recovery/">会话恢复</a> <a class="header-anchor" href="#_4-会话恢复" aria-label="Permalink to &quot;4. [会话恢复](./session-recovery/)&quot;">​</a></h3><p>了解会话恢复机制，自动处理工具调用失败和中断。</p><ul><li>自动处理 tool_result_missing 错误</li><li>修复 thinking_block_order 问题</li><li>配置 auto_resume 和 session_recovery 选项</li></ul><h3 id="_5-请求转换机制" tabindex="-1">5. <a href="./request-transformation/">请求转换机制</a> <a class="header-anchor" href="#_5-请求转换机制" aria-label="Permalink to &quot;5. [请求转换机制](./request-transformation/)&quot;">​</a></h3><p>深入理解请求转换机制，如何兼容不同 AI 模型的协议差异。</p><ul><li>理解 Claude 和 Gemini 模型的协议差异</li><li>排查 Schema 不兼容导致的 400 错误</li><li>优化 Thinking 配置以获得最佳性能</li></ul><h3 id="_6-配置指南" tabindex="-1">6. <a href="./configuration-guide/">配置指南</a> <a class="header-anchor" href="#_6-配置指南" aria-label="Permalink to &quot;6. [配置指南](./configuration-guide/)&quot;">​</a></h3><p>掌握所有配置选项，按需定制插件行为。</p><ul><li>配置文件位置和优先级</li><li>模型行为、账户轮换、应用行为设置</li><li>单账户/多账户/并行代理场景推荐配置</li></ul><h3 id="_7-并行代理优化" tabindex="-1">7. <a href="./parallel-agents/">并行代理优化</a> <a class="header-anchor" href="#_7-并行代理优化" aria-label="Permalink to &quot;7. [并行代理优化](./parallel-agents/)&quot;">​</a></h3><p>为并行代理场景优化账户分配，启用 PID 偏移。</p><ul><li>理解并行代理场景下的账户冲突问题</li><li>启用 PID 偏移让不同进程优先选择不同账户</li><li>配合 round-robin 策略最大化多账户利用率</li></ul><h3 id="_8-调试日志" tabindex="-1">8. <a href="./debug-logging/">调试日志</a> <a class="header-anchor" href="#_8-调试日志" aria-label="Permalink to &quot;8. [调试日志](./debug-logging/)&quot;">​</a></h3><p>启用调试日志，排查问题和监控运行状态。</p><ul><li>启用调试日志记录详细信息</li><li>理解不同日志级别和适用场景</li><li>解读日志内容快速定位问题</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成高级功能学习后，你可以：</p><ul><li>📖 查阅 <a href="./../faq/">常见问题</a> 解决使用中遇到的问题</li><li>📚 阅读 <a href="./../appendix/">附录</a> 了解架构设计和完整配置参考</li><li>🔄 关注 <a href="./../changelog/">更新日志</a> 获取最新功能和变更</li></ul>',32)])])}const _=i(r,[["render",o]]);export{p as __pageData,_ as default};
